class Solution(object):
    def arrayRankTransform(self, arr):
        if not arr:
            return []
        sorted_arr = sorted(set(arr))
        rank_map = {val: i + 1 for i, val in enumerate(sorted_arr)}
        return [rank_map[val] for val in arr]
